1	// CLI: reads JSON scenario from stdin, writes {results:[...]} to stdout.
2	import { readFileSync } from "node:fs";
3	import { quote, claim } from "./claim-office.js";
4	
5	const scenario = JSON.parse(readFileSync(0, "utf-8"));
6	const yearsWithMHPCO = scenario.customer.yearsWithMHPCO;
7	
8	const KNOWN_ITEM_TYPES = new Set([
9	  "sword",
10	  "amulet",
11	  "staff",
12	  "potion",
13	  "rune",
14	  "moonstone",
15	]);
16	
17	function fail(message: string): never {
18	  process.stderr.write(`${message}\n`);
19	  process.exit(1);
20	}
21	
22	function assertKnownItemTypes(items: { type: string }[]): void {
23	  for (const item of items) {
24	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
25	      fail(`Unknown item type: ${item.type}`);
26	    }
27	  }
28	}
29	
30	function assertDamageAmountsNonNegative(
31	  damages: { amount: number }[],
32	): void {
33	  for (const damage of damages) {
34	    if (damage.amount < 0) {
35	      fail(`Negative damage amount: ${damage.amount}`);
36	    }
37	  }
38	}
39	
40	function assertDamagesAreInsured(
41	  items: { type: string }[],
42	  damages: { itemType: string }[],
43	): void {
44	  const insuredTypes = new Set(items.map((item) => item.type));
45	  for (const damage of damages) {
46	    if (!insuredTypes.has(damage.itemType)) {
47	      fail(`Damaged item not in policy: ${damage.itemType}`);
48	    }
49	  }
50	}
51	
52	const results = [];
53	const policies = [];
54	
55	for (const step of scenario.steps) {
56	  if (step.op === "quote") {
57	    assertKnownItemTypes(step.items);
58	    const { premium } = quote({
59	      items: step.items,
60	      yearsWithMHPCO,
61	      firstInsurance: true,
62	      followUp: policies.length > 0,
63	    });
64	    policies.push(step);
65	    results.push({ premium });
66	  } else if (step.op === "claim") {
67	    const items = policies[step.policy].items;
68	    assertDamageAmountsNonNegative(step.incident.damages);
69	    assertDamagesAreInsured(items, step.incident.damages);
70	    const { payout, remainingCap } = claim(items, step.incident);
71	    results.push({ payout, remainingCap });
72	  }
73	}
74	
75	process.stdout.write(JSON.stringify({ results }));
76	process.exit(0);
